/**
 * T7: M6-Frontend-UI -- TaskListItem Component Tests
 *
 * Tests for src/components/TaskListItem.vue:
 * - AC6: Displays title, status badge, priority badge, assignee placeholder, tags placeholder
 * - AC7: Status badge colors: TODO=#6B7280, IN_PROGRESS=#3B82F6, DONE=#10B981, CLOSED=#EF4444
 * - AC8: Priority badge colors: HIGH=#EF4444, MEDIUM=#F59E0B, LOW=#10B981
 * - AC9: Click task item triggers navigation event
 *
 * These tests MUST fail until the implementation file is created.
 *
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi } from 'vitest'
import { mount } from '@vue/test-utils'
import TaskListItem from '@/components/TaskListItem.vue'
import type { Task } from '@/types/task'

// =============================================
// Helpers
// =============================================

function buildTask(overrides: Partial<Task> = {}): Task {
  return {
    id: 1,
    title: 'Test Task Title',
    description: 'Some description',
    priority: 'MEDIUM',
    status: 'TODO',
    createdBy: 1,
    createdAt: '2026-03-06T10:00:00',
    updatedAt: null,
    ...overrides,
  }
}

function mountItem(task: Task) {
  return mount(TaskListItem, {
    props: { task },
  })
}

// =============================================
// AC6: Content rendering
// =============================================
describe('TaskListItem', () => {
  describe('AC6: displays task information', () => {
    it('should render the task title', () => {
      const task = buildTask({ title: 'Deploy to Production' })
      const wrapper = mountItem(task)

      expect(wrapper.text()).toContain('Deploy to Production')
    })

    it('should render a status badge', () => {
      const task = buildTask({ status: 'TODO' })
      const wrapper = mountItem(task)

      expect(wrapper.text()).toContain('TODO')
    })

    it('should render a priority badge', () => {
      const task = buildTask({ priority: 'HIGH' })
      const wrapper = mountItem(task)

      expect(wrapper.text()).toContain('HIGH')
    })

    it('should display assignee placeholder text when no assignee', () => {
      const task = buildTask()
      const wrapper = mountItem(task)

      // M4/M5 not implemented -- placeholder should show
      expect(wrapper.text()).toContain('\u672A\u6307\u6D3E')
    })

    it('should display tags placeholder area', () => {
      const task = buildTask()
      const wrapper = mountItem(task)

      // Tags area should exist even if empty (placeholder)
      expect(wrapper.html()).toBeTruthy()
    })

    it('should render different titles for different tasks', () => {
      const task1 = buildTask({ title: 'Task Alpha' })
      const task2 = buildTask({ title: 'Task Beta' })

      const wrapper1 = mountItem(task1)
      const wrapper2 = mountItem(task2)

      expect(wrapper1.text()).toContain('Task Alpha')
      expect(wrapper1.text()).not.toContain('Task Beta')
      expect(wrapper2.text()).toContain('Task Beta')
      expect(wrapper2.text()).not.toContain('Task Alpha')
    })
  })

  // =============================================
  // AC7: Status badge colors
  // =============================================
  describe('AC7: status badge colors', () => {
    const statusColorMap: Record<string, string> = {
      TODO: '#6B7280',
      IN_PROGRESS: '#3B82F6',
      DONE: '#10B981',
      CLOSED: '#EF4444',
    }

    for (const [status, expectedColor] of Object.entries(statusColorMap)) {
      it(`should render ${status} badge with color ${expectedColor}`, () => {
        const task = buildTask({ status })
        const wrapper = mountItem(task)

        // The badge should contain the status text
        expect(wrapper.text()).toContain(status)

        // The badge should use the correct color (inline style or CSS class)
        const html = wrapper.html()
        expect(html).toContain(expectedColor)
      })
    }
  })

  // =============================================
  // AC8: Priority badge colors
  // =============================================
  describe('AC8: priority badge colors', () => {
    const priorityColorMap: Record<string, string> = {
      HIGH: '#EF4444',
      MEDIUM: '#F59E0B',
      LOW: '#10B981',
    }

    for (const [priority, expectedColor] of Object.entries(priorityColorMap)) {
      it(`should render ${priority} priority badge with color ${expectedColor}`, () => {
        const task = buildTask({ priority })
        const wrapper = mountItem(task)

        expect(wrapper.text()).toContain(priority)

        const html = wrapper.html()
        expect(html).toContain(expectedColor)
      })
    }
  })

  // =============================================
  // AC9: Click event for navigation
  // =============================================
  describe('AC9: click event', () => {
    it('should emit click event when task item is clicked', async () => {
      const task = buildTask({ id: 42 })
      const wrapper = mountItem(task)

      await wrapper.trigger('click')

      expect(wrapper.emitted('click')).toBeTruthy()
    })

    it('should emit click event with the task object or id', async () => {
      const task = buildTask({ id: 99 })
      const wrapper = mountItem(task)

      await wrapper.trigger('click')

      const emitted = wrapper.emitted('click')
      expect(emitted).toBeTruthy()
      expect(emitted!.length).toBeGreaterThan(0)
    })
  })

  // =============================================
  // Edge cases / boundary tests
  // =============================================
  describe('boundary cases', () => {
    it('should handle a task with null description', () => {
      const task = buildTask({ description: null })
      const wrapper = mountItem(task)

      // Should render without error
      expect(wrapper.text()).toContain(task.title)
    })

    it('should handle a very long title gracefully', () => {
      const longTitle = 'A'.repeat(200)
      const task = buildTask({ title: longTitle })
      const wrapper = mountItem(task)

      expect(wrapper.text()).toContain(longTitle)
    })

    it('should handle IN_PROGRESS status text correctly (underscore display)', () => {
      const task = buildTask({ status: 'IN_PROGRESS' })
      const wrapper = mountItem(task)

      // The component should render the status -- may display as IN_PROGRESS or formatted
      expect(wrapper.text()).toContain('IN_PROGRESS')
    })
  })
})

/**
 * T7: M6-Frontend-UI -- TaskFilters Component Tests
 *
 * Tests for src/components/TaskFilters.vue:
 * - AC2: Keyword search input triggers store.setKeyword
 * - AC3: Priority dropdown with All/HIGH/MEDIUM/LOW options triggers store.setPriorityFilter
 * - AC4: Status dropdown with All/TODO/IN_PROGRESS/DONE/CLOSED options triggers store.setStatusFilter
 * - AC5: Multiple filters can coexist (component renders all filter controls)
 *
 * These tests MUST fail until the implementation file is created.
 *
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount } from '@vue/test-utils'
import { setActivePinia, createPinia } from 'pinia'
import TaskFilters from '@/components/TaskFilters.vue'
import { useTaskStore } from '@/stores/taskStore'

// Mock the taskApi so store actions don't hit a real API
vi.mock('@/api/taskApi', () => ({
  fetchTasks: vi.fn().mockResolvedValue({
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
  }),
  createTask: vi.fn(),
  getTask: vi.fn(),
}))

function mountFilters() {
  return mount(TaskFilters, {
    global: {
      plugins: [],
    },
  })
}

describe('TaskFilters', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
  })

  // =============================================
  // Rendering: all filter controls present
  // =============================================
  describe('rendering', () => {
    it('should render a search/keyword input field', () => {
      const wrapper = mountFilters()

      const input = wrapper.find('input[type="text"], input[type="search"], input')
      expect(input.exists()).toBe(true)
    })

    it('should render a priority filter dropdown (select)', () => {
      const wrapper = mountFilters()

      const selects = wrapper.findAll('select')
      // At least one select for priority
      expect(selects.length).toBeGreaterThanOrEqual(1)
    })

    it('should render a status filter dropdown (select)', () => {
      const wrapper = mountFilters()

      const selects = wrapper.findAll('select')
      // Should have at least 2 selects (priority + status)
      expect(selects.length).toBeGreaterThanOrEqual(2)
    })
  })

  // =============================================
  // AC3: Priority dropdown options
  // =============================================
  describe('AC3: priority dropdown options', () => {
    it('should include an "All" option for priority', () => {
      const wrapper = mountFilters()
      const html = wrapper.html()

      // Expect an option that represents "all" (e.g. text or value)
      // This could be in Chinese or English depending on implementation
      const selects = wrapper.findAll('select')
      const prioritySelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some(
          (o) => o.text().includes('HIGH') || o.text().includes('MEDIUM') || o.text().includes('LOW')
        )
      })

      expect(prioritySelect).toBeDefined()
      const options = prioritySelect!.findAll('option')
      // Should have 4 options: All + HIGH + MEDIUM + LOW
      expect(options.length).toBe(4)
    })

    it('should include HIGH, MEDIUM, LOW options', () => {
      const wrapper = mountFilters()
      const html = wrapper.html()

      expect(html).toContain('HIGH')
      expect(html).toContain('MEDIUM')
      expect(html).toContain('LOW')
    })
  })

  // =============================================
  // AC4: Status dropdown options
  // =============================================
  describe('AC4: status dropdown options', () => {
    it('should include an "All" option for status', () => {
      const wrapper = mountFilters()

      const selects = wrapper.findAll('select')
      const statusSelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some(
          (o) =>
            o.text().includes('TODO') ||
            o.text().includes('IN_PROGRESS') ||
            o.text().includes('DONE') ||
            o.text().includes('CLOSED')
        )
      })

      expect(statusSelect).toBeDefined()
      const options = statusSelect!.findAll('option')
      // Should have 5 options: All + TODO + IN_PROGRESS + DONE + CLOSED
      expect(options.length).toBe(5)
    })

    it('should include TODO, IN_PROGRESS, DONE, CLOSED options', () => {
      const wrapper = mountFilters()
      const html = wrapper.html()

      expect(html).toContain('TODO')
      expect(html).toContain('IN_PROGRESS')
      expect(html).toContain('DONE')
      expect(html).toContain('CLOSED')
    })
  })

  // =============================================
  // AC2: Keyword search triggers store action
  // =============================================
  describe('AC2: keyword search triggers store action', () => {
    it('should call store.setKeyword when user types in search input', async () => {
      const wrapper = mountFilters()
      const store = useTaskStore()

      // Spy on the store action
      const setKeywordSpy = vi.spyOn(store, 'setKeyword')

      const input = wrapper.find('input[type="text"], input[type="search"], input')
      await input.setValue('deploy')
      // Trigger the input/change event
      await input.trigger('input')

      // The component may debounce, but the spy should eventually be called
      // For non-debounced: immediate call
      // For debounced: we need to advance timers
      // We'll check that the spy was called OR use fake timers
      vi.useFakeTimers()
      await input.setValue('deploy')
      await input.trigger('input')
      vi.advanceTimersByTime(500) // handle potential debounce of up to 500ms
      vi.useRealTimers()

      expect(setKeywordSpy).toHaveBeenCalled()
    })
  })

  // =============================================
  // AC3: Priority filter triggers store action
  // =============================================
  describe('AC3: priority filter triggers store action', () => {
    it('should call store.setPriorityFilter when priority dropdown changes to HIGH', async () => {
      const wrapper = mountFilters()
      const store = useTaskStore()

      const setPriorityFilterSpy = vi.spyOn(store, 'setPriorityFilter')

      // Find the priority select
      const selects = wrapper.findAll('select')
      const prioritySelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some((o) => o.text().includes('HIGH'))
      })

      expect(prioritySelect).toBeDefined()
      await prioritySelect!.setValue('HIGH')

      expect(setPriorityFilterSpy).toHaveBeenCalledWith('HIGH')
    })

    it('should call store.setPriorityFilter with null when "All" is selected', async () => {
      const wrapper = mountFilters()
      const store = useTaskStore()

      const setPriorityFilterSpy = vi.spyOn(store, 'setPriorityFilter')

      const selects = wrapper.findAll('select')
      const prioritySelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some((o) => o.text().includes('HIGH'))
      })

      expect(prioritySelect).toBeDefined()
      // Select "All" option (value should be empty or null)
      await prioritySelect!.setValue('')

      expect(setPriorityFilterSpy).toHaveBeenCalledWith(null)
    })
  })

  // =============================================
  // AC4: Status filter triggers store action
  // =============================================
  describe('AC4: status filter triggers store action', () => {
    it('should call store.setStatusFilter when status dropdown changes to IN_PROGRESS', async () => {
      const wrapper = mountFilters()
      const store = useTaskStore()

      const setStatusFilterSpy = vi.spyOn(store, 'setStatusFilter')

      const selects = wrapper.findAll('select')
      const statusSelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some((o) => o.text().includes('TODO'))
      })

      expect(statusSelect).toBeDefined()
      await statusSelect!.setValue('IN_PROGRESS')

      expect(setStatusFilterSpy).toHaveBeenCalledWith('IN_PROGRESS')
    })

    it('should call store.setStatusFilter with null when "All" is selected', async () => {
      const wrapper = mountFilters()
      const store = useTaskStore()

      const setStatusFilterSpy = vi.spyOn(store, 'setStatusFilter')

      const selects = wrapper.findAll('select')
      const statusSelect = selects.find((s) => {
        const options = s.findAll('option')
        return options.some((o) => o.text().includes('TODO'))
      })

      expect(statusSelect).toBeDefined()
      await statusSelect!.setValue('')

      expect(setStatusFilterSpy).toHaveBeenCalledWith(null)
    })
  })

  // =============================================
  // AC5: Multiple filters coexist
  // =============================================
  describe('AC5: multiple filters can coexist', () => {
    it('should render all three filter controls simultaneously', () => {
      const wrapper = mountFilters()

      const input = wrapper.find('input')
      const selects = wrapper.findAll('select')

      expect(input.exists()).toBe(true)
      expect(selects.length).toBeGreaterThanOrEqual(2)
    })
  })
})

/**
 * T7: M6-Frontend-UI -- TaskCreateForm Component Tests
 *
 * Tests for src/components/TaskCreateForm.vue:
 * - AC10: visible prop controls form display
 * - AC11: Form has title (required), description (optional), priority dropdown (default MEDIUM), submit
 * - AC12: After create success, emits 'created' event
 * - Form validation: title is required
 * - Cancel emits 'cancel' event
 *
 * These tests MUST fail until the implementation file is created.
 *
 * @vitest-environment jsdom
 */
import { describe, it, expect, vi, beforeEach } from 'vitest'
import { mount } from '@vue/test-utils'
import { setActivePinia, createPinia } from 'pinia'
import TaskCreateForm from '@/components/TaskCreateForm.vue'
import { useTaskStore } from '@/stores/taskStore'

// Mock the taskApi
vi.mock('@/api/taskApi', () => ({
  fetchTasks: vi.fn().mockResolvedValue({
    content: [],
    page: 0,
    size: 20,
    totalElements: 0,
    totalPages: 0,
  }),
  createTask: vi.fn().mockResolvedValue({
    id: 1,
    title: 'Created',
    description: null,
    priority: 'MEDIUM',
    status: 'TODO',
    createdBy: 1,
    createdAt: '2026-03-06T10:00:00',
    updatedAt: null,
  }),
  getTask: vi.fn(),
}))

function mountForm(props: { visible: boolean } = { visible: true }) {
  return mount(TaskCreateForm, {
    props,
  })
}

describe('TaskCreateForm', () => {
  beforeEach(() => {
    setActivePinia(createPinia())
    vi.clearAllMocks()
  })

  // =============================================
  // AC10: visible prop controls display
  // =============================================
  describe('AC10: visible prop', () => {
    it('should be visible when visible=true', () => {
      const wrapper = mountForm({ visible: true })

      // The form should render content
      expect(wrapper.isVisible()).toBe(true)
    })

    it('should be hidden or not render form content when visible=false', () => {
      const wrapper = mountForm({ visible: false })

      // Either the component is hidden via v-show or not rendered via v-if
      // Check that the form element is not visible or doesn't exist
      const form = wrapper.find('form')
      if (form.exists()) {
        expect(form.isVisible()).toBe(false)
      } else {
        // v-if case: no form rendered at all
        expect(wrapper.find('input').exists()).toBe(false)
      }
    })
  })

  // =============================================
  // AC11: Form fields
  // =============================================
  describe('AC11: form fields', () => {
    it('should have a title input field', () => {
      const wrapper = mountForm()

      // Look for an input that serves as the title field
      const inputs = wrapper.findAll('input[type="text"], input:not([type])')
      expect(inputs.length).toBeGreaterThanOrEqual(1)
    })

    it('should have a description textarea or input', () => {
      const wrapper = mountForm()

      const textarea = wrapper.find('textarea')
      const descInput = wrapper.findAll('input').filter((i) => {
        const placeholder = i.attributes('placeholder') || ''
        const name = i.attributes('name') || ''
        return placeholder.toLowerCase().includes('desc') || name.toLowerCase().includes('desc')
      })

      // Either a textarea or an input for description
      expect(textarea.exists() || descInput.length > 0).toBe(true)
    })

    it('should have a priority dropdown (select) with HIGH, MEDIUM, LOW options', () => {
      const wrapper = mountForm()

      const select = wrapper.find('select')
      expect(select.exists()).toBe(true)

      const options = select.findAll('option')
      const optionTexts = options.map((o) => o.text())
      const optionValues = options.map((o) => o.attributes('value') || o.text())

      // Should contain HIGH, MEDIUM, LOW
      const allValues = [...optionTexts, ...optionValues].join(' ')
      expect(allValues).toContain('HIGH')
      expect(allValues).toContain('MEDIUM')
      expect(allValues).toContain('LOW')
    })

    it('should default priority to MEDIUM', () => {
      const wrapper = mountForm()

      const select = wrapper.find('select')
      expect(select.exists()).toBe(true)

      // The selected value should be MEDIUM by default
      expect((select.element as HTMLSelectElement).value).toBe('MEDIUM')
    })

    it('should have a submit button', () => {
      const wrapper = mountForm()

      const submitBtn = wrapper.find('button[type="submit"], button')
      expect(submitBtn.exists()).toBe(true)
    })
  })

  // =============================================
  // AC11: Title is required (validation)
  // =============================================
  describe('AC11: title validation', () => {
    it('should not submit when title is empty', async () => {
      const wrapper = mountForm()
      const store = useTaskStore()
      const createTaskSpy = vi.spyOn(store, 'createTask')

      // Find the form and submit without filling title
      const form = wrapper.find('form')
      if (form.exists()) {
        await form.trigger('submit.prevent')
      } else {
        // Try submitting via button click
        const submitBtn = wrapper.find('button[type="submit"]')
        if (submitBtn.exists()) {
          await submitBtn.trigger('click')
        }
      }

      // createTask should NOT have been called
      expect(createTaskSpy).not.toHaveBeenCalled()
    })

    it('should mark title field as required', () => {
      const wrapper = mountForm()

      const titleInput = wrapper.find('input')
      if (titleInput.exists()) {
        // Check for required attribute or aria-required
        const hasRequired =
          titleInput.attributes('required') !== undefined ||
          titleInput.attributes('aria-required') === 'true'
        expect(hasRequired).toBe(true)
      }
    })
  })

  // =============================================
  // AC11 + AC12: Successful submission
  // =============================================
  describe('AC11+AC12: form submission', () => {
    it('should call store.createTask with form data when submitted with valid title', async () => {
      const wrapper = mountForm()
      const store = useTaskStore()
      const createTaskSpy = vi.spyOn(store, 'createTask').mockResolvedValue(undefined as any)

      // Fill in the title
      const titleInput = wrapper.find('input')
      await titleInput.setValue('New Task Title')

      // Submit the form
      const form = wrapper.find('form')
      if (form.exists()) {
        await form.trigger('submit.prevent')
      } else {
        const submitBtn = wrapper.find('button[type="submit"]')
        if (submitBtn.exists()) {
          await submitBtn.trigger('click')
        }
      }

      expect(createTaskSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          title: 'New Task Title',
        })
      )
    })

    it('should include priority in the submitted data', async () => {
      const wrapper = mountForm()
      const store = useTaskStore()
      const createTaskSpy = vi.spyOn(store, 'createTask').mockResolvedValue(undefined as any)

      // Fill in title
      const titleInput = wrapper.find('input')
      await titleInput.setValue('Task with Priority')

      // Change priority to HIGH
      const select = wrapper.find('select')
      await select.setValue('HIGH')

      // Submit
      const form = wrapper.find('form')
      if (form.exists()) {
        await form.trigger('submit.prevent')
      } else {
        const submitBtn = wrapper.find('button[type="submit"]')
        if (submitBtn.exists()) {
          await submitBtn.trigger('click')
        }
      }

      expect(createTaskSpy).toHaveBeenCalledWith(
        expect.objectContaining({
          title: 'Task with Priority',
          priority: 'HIGH',
        })
      )
    })

    it('should emit "created" event after successful creation', async () => {
      const wrapper = mountForm()
      const store = useTaskStore()
      vi.spyOn(store, 'createTask').mockResolvedValue(undefined as any)

      // Fill and submit
      const titleInput = wrapper.find('input')
      await titleInput.setValue('Success Task')

      const form = wrapper.find('form')
      if (form.exists()) {
        await form.trigger('submit.prevent')
      } else {
        const submitBtn = wrapper.find('button[type="submit"]')
        if (submitBtn.exists()) {
          await submitBtn.trigger('click')
        }
      }

      // Wait for async operations
      await vi.dynamicImportSettled?.() // if available
      await wrapper.vm.$nextTick()

      expect(wrapper.emitted('created')).toBeTruthy()
    })
  })

  // =============================================
  // Cancel behavior
  // =============================================
  describe('cancel', () => {
    it('should emit "cancel" event when cancel button is clicked', async () => {
      const wrapper = mountForm()

      // Find the cancel button (not the submit button)
      const buttons = wrapper.findAll('button')
      const cancelBtn = buttons.find((btn) => {
        const text = btn.text().toLowerCase()
        return (
          text.includes('cancel') ||
          text.includes('\u53D6\u6D88') ||
          btn.attributes('type') !== 'submit'
        )
      })

      expect(cancelBtn).toBeDefined()
      await cancelBtn!.trigger('click')

      expect(wrapper.emitted('cancel')).toBeTruthy()
    })
  })

  // =============================================
  // Boundary cases
  // =============================================
  describe('boundary cases', () => {
    it('should handle title with maximum length (200 chars)', async () => {
      const wrapper = mountForm()
      const store = useTaskStore()
      vi.spyOn(store, 'createTask').mockResolvedValue(undefined as any)

      const maxTitle = 'A'.repeat(200)
